1	//! Elementwise op methods on [`Tensor`].
2	//!
3	//! Method implementations are generated by the [`unary_method!`] and
4	//! [`binary_method!`] macros to keep the per-file function count low
5	//! while still giving ergonomic `tensor.add(&other)` / `tensor.exp()`
6	//! call sites.
7	
8	use std::rc::Rc;
9	
10	use crate::ops::{BinaryOp, UnaryOp};
11	use crate::tape::{NodeData, NodeKind};
12	use crate::tensor::Tensor;
13	
14	pub(crate) fn push_unary(t: &Tensor, op: UnaryOp) -> Tensor {
15	    let x = t.value();
16	    let y = op.forward(&x);
17	    let node = t.tape.push(NodeData {
18	        value: y,
19	        grad: None,
20	        kind: NodeKind::Unary { op, parent: t.node },
21	        requires_grad: false,
22	    });
23	    Tensor {
24	        node,
25	        tape: Rc::clone(&t.tape),
26	    }
27	}
28	
29	pub(crate) fn push_binary(a: &Tensor, b: &Tensor, op: BinaryOp) -> Tensor {
30	    let av = a.value();
31	    let bv = b.value();
32	    let v = op.forward(&av, &bv).expect("broadcastable shapes");
33	    let node = a.tape.push(NodeData {
34	        value: v,
35	        grad: None,
36	        kind: NodeKind::Binary {
37	            op,
38	            left: a.node,
39	            right: b.node,
40	        },
41	        requires_grad: false,
42	    });
43	    Tensor {
44	        node,
45	        tape: Rc::clone(&a.tape),
46	    }
47	}
48	
49	macro_rules! unary_method {
50	    ($name:ident, $variant:ident, $doc:expr) => {
51	        #[doc = $doc]
52	        #[must_use]
