1	//! Array operations: reshape, transpose, element-wise arithmetic.
2	
3	use crate::dense::DenseArray;
4	use crate::error::ArrayError;
5	use crate::shape::Shape;
6	
7	impl DenseArray {
8	    /// Reshape to a new shape, preserving element order.
9	    ///
10	    /// Succeeds only when the new shape has the same element count.
11	    pub fn reshape(&self, new_shape: Shape) -> Result<DenseArray, ArrayError> {
12	        let source = self.elem_count();
13	        let target = new_shape.elem_count();
14	        if source != target {
15	            return Err(ArrayError::ShapeMismatch { source, target });
16	        }
17	        Ok(DenseArray {
18	            shape: new_shape,
19	            data: self.data.clone(),
20	        })
21	    }
22	
23	    /// Transpose: reverse axis order and reorder data to row-major.
24	    ///
25	    /// - Scalar/vector: returns a clone (identity).
26	    /// - Matrix and higher: reverses dims and physically reorders data.
27	    #[must_use]
28	    pub fn transpose(&self) -> DenseArray {
29	        let dims = self.shape().dims();
30	        if dims.len() <= 1 {
31	            return self.clone();
32	        }
33	
34	        let new_dims: Vec<usize> = dims.iter().rev().copied().collect();
35	        let new_shape = Shape::new(new_dims);
36	        let n = self.elem_count();
37	        let mut new_data = vec![0.0; n];
38	
39	        let rank = dims.len();
40	        let old_strides = compute_strides(dims);
41	        let new_strides = compute_strides(new_shape.dims());
42	
43	        for flat in 0..n {
44	            let mut remainder = flat;
45	            let mut new_flat = 0;
46	            for axis in 0..rank {
47	                let idx = remainder / old_strides[axis];
48	                remainder %= old_strides[axis];
49	                new_flat += idx * new_strides[rank - 1 - axis];
50	            }
51	            new_data[new_flat] = self.data[flat];
52	        }
53	
54	        DenseArray {
55	            shape: new_shape,
56	            data: new_data,
57	        }
58	    }
59	}
60	
61	impl DenseArray {
62	    /// Apply a binary operation element-wise with scalar broadcasting.
63	    ///
64	    /// - Same shape: element-wise.
65	    /// - One scalar: broadcast to the other's shape.
66	    /// - Otherwise: ShapeMismatch error.
67	    pub fn apply_binop(
68	        &self,
69	        other: &DenseArray,
70	        op: fn(f64, f64) -> f64,
71	    ) -> Result<DenseArray, ArrayError> {
72	        if self.shape() == other.shape() {
73	            let data: Vec<f64> = self
74	                .data()
75	                .iter()
76	                .zip(other.data().iter())
77	                .map(|(a, b)| op(*a, *b))
78	                .collect();
79	            return Ok(DenseArray {
80	                shape: self.shape.clone(),
81	                data,
82	            });
83	        }
84	        // Scalar broadcast
85	        if self.rank() == 0 {
86	            let s = self.data()[0];
87	            let data: Vec<f64> = other.data().iter().map(|b| op(s, *b)).collect();
88	            return Ok(DenseArray {
89	                shape: other.shape.clone(),
90	                data,
91	            });
92	        }
93	        if other.rank() == 0 {
94	            let s = other.data()[0];
95	            let data: Vec<f64> = self.data().iter().map(|a| op(*a, s)).collect();
96	            return Ok(DenseArray {
97	                shape: self.shape.clone(),
98	                data,
99	            });
100	        }
101	        Err(ArrayError::ShapeMismatch {
102	            source: self.elem_count(),
103	            target: other.elem_count(),
104	        })
105	    }
106	}
107	
108	impl DenseArray {
109	    /// Dot product of two rank-1 vectors.
110	    ///
111	    /// Both must be vectors of the same length. Returns a scalar.
112	    pub fn dot(&self, other: &DenseArray) -> Result<DenseArray, ArrayError> {
113	        if self.rank() != 1 || other.rank() != 1 {
114	            return Err(ArrayError::RankMismatch {
115	                expected: 1,
116	                got: if self.rank() != 1 {
117	                    self.rank()
118	                } else {
119	                    other.rank()
120	                },
121	            });
122	        }
123	        if self.elem_count() != other.elem_count() {
124	            return Err(ArrayError::ShapeMismatch {
125	                source: self.elem_count(),
126	                target: other.elem_count(),
127	            });
128	        }
129	        let sum: f64 = self
130	            .data()
131	            .iter()
132	            .zip(other.data().iter())
133	            .map(|(a, b)| a * b)
134	            .sum();
135	        Ok(DenseArray::from_scalar(sum))
136	    }
137	}
138	
139	impl DenseArray {
140	    /// Matrix multiplication.
141	    ///
142	    /// - [m, k] * [k, n] -> [m, n]
143	    /// - [m, k] * [k] -> [m] (matrix-vector product)
144	    pub fn matmul(&self, other: &DenseArray) -> Result<DenseArray, ArrayError> {
145	        let (m, k) = match self.shape().dims() {
146	            [m, k] => (*m, *k),
147	            _ => {
148	                return Err(ArrayError::RankMismatch {
149	                    expected: 2,
150	                    got: self.rank(),
151	                });
152	            }
153	        };
154	        match other.shape().dims() {
155	            [k2, n] if *k2 == k => {
156	                let n = *n;
157	                let data: Vec<f64> = self
158	                    .data
159	                    .chunks(k)
160	                    .flat_map(|row| {
161	                        (0..n).map(move |j| {
162	                            row.iter()
163	                                .zip(other.data.chunks(n).map(|col| col[j]))
164	                                .map(|(a, b)| a * b)
165	                                .sum::<f64>()
166	                        })
167	                    })
168	                    .collect();
169	                Ok(DenseArray {
170	                    shape: Shape::new(vec![m, n]),
171	                    data,
172	                })
173	            }
174	            [k2] if *k2 == k => {
175	                let data: Vec<f64> = self
176	                    .data
177	                    .chunks(k)
178	                    .map(|row| row.iter().zip(other.data.iter()).map(|(a, b)| a * b).sum())
179	                    .collect();
180	                Ok(DenseArray {
181	                    shape: Shape::vector(m),
182	                    data,
183	                })
184	            }
185	            _ => Err(ArrayError::ShapeMismatch {
186	                source: k,
187	                target: other.shape().dims().first().copied().unwrap_or(0),
188	            }),
189	        }
190	    }
191	}
192	
193	impl DenseArray {
194	    /// Reduce along an axis using the given binary operation.
195	    ///
196	    /// Removes the specified axis from the shape. For example,
197	    /// a [2,3] array reduced along axis 0 produces a [3] result.
198	    pub fn reduce_axis(
199	        &self,
200	        axis: usize,
201	        identity: f64,
202	        op: fn(f64, f64) -> f64,
203	    ) -> Result<DenseArray, ArrayError> {
204	        let dims = self.shape().dims();
205	        if axis >= dims.len() {
206	            return Err(ArrayError::IndexOutOfBounds {
207	                axis,
208	                index: axis,
209	                size: dims.len(),
210	            });
211	        }
212	        let mut result_dims: Vec<usize> = dims.to_vec();
213	        result_dims.remove(axis);
214	        let result_shape = Shape::new(result_dims);
215	        let result_count = result_shape.elem_count();
216	        let mut result_data = vec![identity; result_count];
217	
218	        let strides = compute_strides(dims);
219	        let axis_size = dims[axis];
220	        let axis_stride = strides[axis];
221	
222	        for flat in 0..self.elem_count() {
223	            let result_flat = if axis_stride > 1 {
224	                let outer = flat / (axis_size * axis_stride);
225	                let inner = flat % axis_stride;
226	                outer * axis_stride + inner
227	            } else {
228	                flat / axis_size
229	            };
230	            result_data[result_flat] = op(result_data[result_flat], self.data[flat]);
231	        }
232	
233	        Ok(DenseArray {
234	            shape: result_shape,
235	            data: result_data,
236	        })
237	    }
238	}
239	
240	impl DenseArray {
241	    /// Argmax along an axis. Returns an array with the given axis
242	    /// removed whose values are the indices (as f64) of the maxima.
243	    /// Ties go to the first occurrence.
244	    pub fn argmax_axis(&self, axis: usize) -> Result<DenseArray, ArrayError> {
245	        let dims = self.shape().dims();
246	        if axis >= dims.len() {
247	            return Err(ArrayError::IndexOutOfBounds {
248	                axis,
249	                index: axis,
250	                size: dims.len(),
251	            });
252	        }
253	        let mut result_dims: Vec<usize> = dims.to_vec();
254	        result_dims.remove(axis);
