fn grad_sum_vector() {
    let x_arr = DenseArray::from_vec(vec![1.0, -2.0, 3.0, 0.5]);
    let tape = Tape::new();
    let x = Tensor::param(tape, x_arr.clone());
    let y = x.sum();
    y.backward();
    let ag = x.grad().expect("grad");
    let num = fd_grad(&x_arr, |xv| {
        let tape = Tape::new();
        let t = Tensor::leaf(tape, xv.clone(), false);
        sum_data(&t.sum())
    });
    assert_close(&ag, &num);
}

