//! Numerically-stable softmax forward and backward along an axis.

use mlpl_array::DenseArray;

/// Numerically-stable softmax along `axis` (supports rank-1 and rank-2).
#[must_use]
pub fn softmax_forward(x: &DenseArray, axis: usize) -> DenseArray {
    let dims = x.shape().dims().to_vec();
    match dims.len() {
        0 => x.clone(),
        1 => {
            let data = softmax_row(x.data());
            DenseArray::new(x.shape().clone(), data).expect("shape")
        }
        2 => softmax_2d_forward(x, axis, dims[0], dims[1]),
        _ => panic!("softmax supports rank <= 2"),
    }
}

fn softmax_2d_forward(x: &DenseArray, axis: usize, rows: usize, cols: usize) -> DenseArray {
    let mut out = vec![0.0; rows * cols];
    if axis == 1 {
        for r in 0..rows {
            let row = &x.data()[r * cols..(r + 1) * cols];
            let sm = softmax_row(row);
            out[r * cols..(r + 1) * cols].copy_from_slice(&sm);
        }
    } else {
        for c in 0..cols {
            let col: Vec<f64> = (0..rows).map(|r| x.data()[r * cols + c]).collect();
            let sm = softmax_row(&col);
            for (r, v) in sm.iter().enumerate() {
                out[r * cols + c] = *v;
            }
        }
    }
    DenseArray::new(x.shape().clone(), out).expect("shape")
}

fn softmax_row(row: &[f64]) -> Vec<f64> {
    let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = row.iter().map(|v| (v - m).exp()).collect();
    let s: f64 = exps.iter().sum();
    exps.into_iter().map(|e| e / s).collect()
}

/// Softmax backward given forward output `y` and upstream `g`, along `axis`.
///
/// For each row: dx_i = y_i * (g_i - sum_j(g_j * y_j))
#[must_use]
pub fn softmax_backward(y: &DenseArray, upstream: &DenseArray, axis: usize) -> DenseArray {
    let dims = y.shape().dims().to_vec();
    match dims.len() {
        0 => DenseArray::from_scalar(0.0),
        1 => {
            let data = softmax_row_backward(y.data(), upstream.data());
            DenseArray::new(y.shape().clone(), data).expect("shape")
        }
        2 => softmax_2d_backward(y, upstream, axis, dims[0], dims[1]),
        _ => panic!("softmax supports rank <= 2"),
    }
}

fn softmax_2d_backward(
    y: &DenseArray,
    upstream: &DenseArray,
    axis: usize,
    rows: usize,
    cols: usize,
) -> DenseArray {
    let mut out = vec![0.0; rows * cols];
    if axis == 1 {
        for r in 0..rows {
            let yr = &y.data()[r * cols..(r + 1) * cols];
            let gr = &upstream.data()[r * cols..(r + 1) * cols];
            let dx = softmax_row_backward(yr, gr);
            out[r * cols..(r + 1) * cols].copy_from_slice(&dx);
        }
    } else {
        for c in 0..cols {
            let yc: Vec<f64> = (0..rows).map(|r| y.data()[r * cols + c]).collect();
