//! Op enums and forward/backward helpers for autograd nodes.

use mlpl_array::{DenseArray, Shape};

/// Unary elementwise op.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum UnaryOp {
    /// -x
    Neg,
    /// exp(x)
    Exp,
    /// natural log
    Log,
    /// max(0, x)
    Relu,
    /// tanh(x)
    Tanh,
    /// 1 / (1 + exp(-x))
    Sigmoid,
}

/// Binary elementwise op.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BinaryOp {
    /// a + b
    Add,
    /// a - b
    Sub,
    /// a * b
    Mul,
    /// a / b
    Div,
}

impl UnaryOp {
    /// Forward pass: apply the op elementwise.
    #[must_use]
    pub fn forward(self, x: &DenseArray) -> DenseArray {
        let f: fn(f64) -> f64 = match self {
            Self::Neg => |v| -v,
            Self::Exp => f64::exp,
            Self::Log => f64::ln,
            Self::Relu => |v| v.max(0.0),
            Self::Tanh => f64::tanh,
            Self::Sigmoid => |v| 1.0 / (1.0 + (-v).exp()),
        };
        x.map(f)
    }

    /// Compute local gradient wrt input x given upstream gradient.
    ///
    /// `x` is the parent input; `y` is the forward output (cached).
    #[must_use]
    pub fn backward(self, x: &DenseArray, y: &DenseArray, upstream: &DenseArray) -> DenseArray {
        let n = upstream.data().len();
        let mut out = Vec::with_capacity(n);
        for i in 0..n {
            let xi = x.data()[i];
            let yi = y.data()[i];
            let g = upstream.data()[i];
            let local = match self {
                Self::Neg => -1.0,
                Self::Exp => yi,
                Self::Log => 1.0 / xi,
                Self::Relu => {
                    if xi > 0.0 {
                        1.0
                    } else {
                        0.0
                    }
                }
                Self::Tanh => 1.0 - yi * yi,
                Self::Sigmoid => yi * (1.0 - yi),
            };
            out.push(g * local);
        }
        DenseArray::new(upstream.shape().clone(), out).expect("shape preserved")
    }
}

impl BinaryOp {
    /// Forward pass with scalar broadcasting.
    pub fn forward(
        self,
        a: &DenseArray,
        b: &DenseArray,
    ) -> Result<DenseArray, mlpl_array::ArrayError> {
        let op: fn(f64, f64) -> f64 = match self {
            Self::Add => |x, y| x + y,
            Self::Sub => |x, y| x - y,
            Self::Mul => |x, y| x * y,
            Self::Div => |x, y| x / y,
        };
        a.apply_binop(b, op)
    }

    /// Compute upstream gradients for the two parents.
    ///
    /// Returns `(grad_a, grad_b)`, each shaped like the upstream grad
    /// (caller is responsible for un-broadcasting to the parent shape).
    #[must_use]
    pub fn backward(
        self,
        a_val: &DenseArray,
        b_val: &DenseArray,
        upstream: &DenseArray,
    ) -> (DenseArray, DenseArray) {
        let n = upstream.data().len();
        let mut ga = Vec::with_capacity(n);
        let mut gb = Vec::with_capacity(n);
        for i in 0..n {
            let g = upstream.data()[i];
            // Index parents by broadcast: scalars reuse index 0.
            let ai = if a_val.data().len() == 1 {
                a_val.data()[0]
            } else {
                a_val.data()[i]
            };
            let bi = if b_val.data().len() == 1 {
                b_val.data()[0]
            } else {
                b_val.data()[i]
            };
            match self {
                Self::Add => {
                    ga.push(g);
                    gb.push(g);
                }
                Self::Sub => {
                    ga.push(g);
                    gb.push(-g);
                }
                Self::Mul => {
                    ga.push(g * bi);
                    gb.push(g * ai);
                }
                Self::Div => {
                    ga.push(g / bi);
                    gb.push(-g * ai / (bi * bi));
                }
            }
        }
        let shape = upstream.shape().clone();
        (
            DenseArray::new(shape.clone(), ga).expect("shape"),
            DenseArray::new(shape, gb).expect("shape"),
        )
    }
}

/// Numerically-stable softmax along `axis` (supports rank-1 and rank-2).
///
/// For rank-0, returns a clone. For rank-1, runs over the single row.
/// For rank-2 with `axis == 1`, runs per row. `axis == 0` transposes.
#[must_use]
pub fn softmax_forward(x: &DenseArray, axis: usize) -> DenseArray {
    let dims = x.shape().dims().to_vec();
    match dims.len() {
        0 => x.clone(),
        1 => {
            let data = softmax_row(x.data());
            DenseArray::new(x.shape().clone(), data).expect("shape")
        }
        2 => {
            let (rows, cols) = (dims[0], dims[1]);
            let mut out = vec![0.0; rows * cols];
            if axis == 1 {
                for r in 0..rows {
                    let row = &x.data()[r * cols..(r + 1) * cols];
                    let sm = softmax_row(row);
                    out[r * cols..(r + 1) * cols].copy_from_slice(&sm);
                }
                DenseArray::new(x.shape().clone(), out).expect("shape")
            } else {
                // axis 0: softmax down columns.
                for c in 0..cols {
                    let col: Vec<f64> = (0..rows).map(|r| x.data()[r * cols + c]).collect();
                    let sm = softmax_row(&col);
                    for r in 0..rows {
                        out[r * cols + c] = sm[r];
                    }
                }
                DenseArray::new(x.shape().clone(), out).expect("shape")
            }
        }
        _ => panic!("softmax supports rank <= 2"),
    }
}

fn softmax_row(row: &[f64]) -> Vec<f64> {
    let m = row.iter().copied().fold(f64::NEG_INFINITY, f64::max);
    let exps: Vec<f64> = row.iter().map(|v| (v - m).exp()).collect();
    let s: f64 = exps.iter().sum();
    exps.into_iter().map(|e| e / s).collect()
}

/// Softmax backward given forward output `y` and upstream `g`, along `axis`.
///
/// For each row: dx_i = y_i * (g_i - sum_j(g_j * y_j))
#[must_use]
pub fn softmax_backward(y: &DenseArray, upstream: &DenseArray, axis: usize) -> DenseArray {
    let dims = y.shape().dims().to_vec();
    match dims.len() {
        0 => DenseArray::from_scalar(0.0),
        1 => {
            let data = softmax_row_backward(y.data(), upstream.data());
            DenseArray::new(y.shape().clone(), data).expect("shape")
        }
        2 => {
            let (rows, cols) = (dims[0], dims[1]);
            let mut out = vec![0.0; rows * cols];
            if axis == 1 {
                for r in 0..rows {
                    let yr = &y.data()[r * cols..(r + 1) * cols];
                    let gr = &upstream.data()[r * cols..(r + 1) * cols];
                    let dx = softmax_row_backward(yr, gr);
                    out[r * cols..(r + 1) * cols].copy_from_slice(&dx);
                }
            } else {
                for c in 0..cols {
                    let yc: Vec<f64> = (0..rows).map(|r| y.data()[r * cols + c]).collect();
                    let gc: Vec<f64> = (0..rows).map(|r| upstream.data()[r * cols + c]).collect();
                    let dx = softmax_row_backward(&yc, &gc);
                    for r in 0..rows {
                        out[r * cols + c] = dx[r];
                    }
                }
            }
            DenseArray::new(y.shape().clone(), out).expect("shape")
        }
        _ => panic!("softmax supports rank <= 2"),
    }
}

fn softmax_row_backward(y: &[f64], g: &[f64]) -> Vec<f64> {
    let dot: f64 = y.iter().zip(g.iter()).map(|(yi, gi)| yi * gi).sum();
    y.iter()
        .zip(g.iter())
        .map(|(yi, gi)| yi * (gi - dot))
        .collect()
}

/// Sum `grad` (shaped like the broadcasted result) down to `target_shape`
/// (the parent's original shape). Handles the scalar-broadcast case.
#[must_use]
pub fn unbroadcast(grad: DenseArray, target_shape: &Shape) -> DenseArray {
    if grad.shape() == target_shape {
        return grad;
    }
    // target was a scalar that got broadcast to grad.shape(); sum it.
    if target_shape.rank() == 0 {
        let s: f64 = grad.data().iter().sum();
        return DenseArray::from_scalar(s);
    }
    // Shapes should match otherwise; keep a safe fallback.
    grad
}

/// Accumulate `incoming` into `slot`: add if already present, else set.
pub fn accumulate(slot: &mut Option<DenseArray>, incoming: DenseArray) {
    match slot {
        None => *slot = Some(incoming),
        Some(existing) => {
            let sum = existing
                .apply_binop(&incoming, |a, b| a + b)
                .expect("matching shapes during accumulation");
            *existing = sum;
        }
    }
}

