    }
    // target was a scalar that got broadcast to grad.shape(); sum it.
    if target_shape.rank() == 0 {
        let s: f64 = grad.data().iter().sum();
        return DenseArray::from_scalar(s);
    }
    // Shapes should match otherwise; keep a safe fallback.
    grad
}

