//! Reverse-mode backward pass.

use mlpl_array::DenseArray;

use crate::ops::{accumulate, softmax_backward, unbroadcast};
use crate::tape::{NodeId, NodeKind, Tape};

/// Run a backward pass rooted at `root`, seeding `d root / d root = 1`.
///
/// Walks nodes in reverse topological order (descending node id is
/// safe since ops always append after their parents).
pub fn backward(tape: &Tape, root: NodeId) {
    seed_root(tape, root);
    let len = tape.len();
    for idx in (0..len).rev() {
        propagate(tape, NodeId(idx));
    }
}

fn seed_root(tape: &Tape, root: NodeId) {
    let mut nodes = tape.nodes_mut();
    let node = &mut nodes[root.0];
    if node.grad.is_none() {
        let ones = vec![1.0; node.value.data().len()];
        node.grad = Some(DenseArray::new(node.value.shape().clone(), ones).expect("shape"));
    }
}

fn propagate(tape: &Tape, id: NodeId) {
    let (kind, upstream) = {
        let nodes = tape.nodes();
        let node = &nodes[id.0];
        let Some(upstream) = node.grad.clone() else {
            return;
        };
        (node.kind.clone(), upstream)
    };

    match kind {
        NodeKind::Leaf => {}
        NodeKind::Unary { op, parent } => {
            let x = tape.nodes()[parent.0].value.clone();
            let y = tape.nodes()[id.0].value.clone();
            let grad_x = op.backward(&x, &y, &upstream);
            let target_shape = tape.nodes()[parent.0].value.shape().clone();
            let grad_x = unbroadcast(grad_x, &target_shape);
            let mut nodes = tape.nodes_mut();
            accumulate(&mut nodes[parent.0].grad, grad_x);
        }
        NodeKind::Binary { op, left, right } => {
            let a = tape.nodes()[left.0].value.clone();
            let b = tape.nodes()[right.0].value.clone();
            let (ga, gb) = op.backward(&a, &b, &upstream);
            let left_shape = tape.nodes()[left.0].value.shape().clone();
            let right_shape = tape.nodes()[right.0].value.shape().clone();
            let ga = unbroadcast(ga, &left_shape);
            let gb = unbroadcast(gb, &right_shape);
            let mut nodes = tape.nodes_mut();
            accumulate(&mut nodes[left.0].grad, ga);
            accumulate(&mut nodes[right.0].grad, gb);
        }
        NodeKind::SumAll { parent } => {
            let g = upstream.data()[0];
            let parent_shape = tape.nodes()[parent.0].value.shape().clone();
            let n = parent_shape.elem_count();
            let grad = DenseArray::new(parent_shape, vec![g; n]).expect("shape");
            let mut nodes = tape.nodes_mut();
            accumulate(&mut nodes[parent.0].grad, grad);
        }
        NodeKind::MeanAll { parent } => {
            let parent_shape = tape.nodes()[parent.0].value.shape().clone();
            let n = parent_shape.elem_count();
            let g = upstream.data()[0] / n as f64;
            let grad = DenseArray::new(parent_shape, vec![g; n]).expect("shape");
            let mut nodes = tape.nodes_mut();
            accumulate(&mut nodes[parent.0].grad, grad);
        }
        NodeKind::Softmax { parent, axis } => {
            let y = tape.nodes()[id.0].value.clone();
            let grad = softmax_backward(&y, &upstream, axis);
            let mut nodes = tape.nodes_mut();
            accumulate(&mut nodes[parent.0].grad, grad);
        }
        NodeKind::Transpose { parent } => {
            let grad = upstream.transpose();
            let mut nodes = tape.nodes_mut();
            accumulate(&mut nodes[parent.0].grad, grad);
        }
        NodeKind::Reshape { parent, orig_shape } => {
            let grad = upstream.reshape(orig_shape).expect("reshape back");
            let mut nodes = tape.nodes_mut();
            accumulate(&mut nodes[parent.0].grad, grad);
        }
        NodeKind::MatMul { left, right } => {
            let a = tape.nodes()[left.0].value.clone();
            let b = tape.nodes()[right.0].value.clone();
            // grad_a = upstream @ b^T ; grad_b = a^T @ upstream
            let ga = matmul_upstream_bt(&upstream, &b);
            let gb = a.transpose().matmul(&upstream).expect("matmul grad_b");
            let mut nodes = tape.nodes_mut();
            accumulate(&mut nodes[left.0].grad, ga);
            accumulate(&mut nodes[right.0].grad, gb);
        }
    }
}

fn matmul_upstream_bt(upstream: &DenseArray, b: &DenseArray) -> DenseArray {
    // Handle matrix-vector case where b is rank-1: upstream is rank-1 [m],
    // grad_a = outer(upstream, b). Otherwise standard upstream @ b^T.
    if b.shape().rank() == 1 {
        let m = upstream.shape().dims()[0];
        let k = b.shape().dims()[0];
        let mut data = vec![0.0; m * k];
        for i in 0..m {
            for j in 0..k {
                data[i * k + j] = upstream.data()[i] * b.data()[j];
            }
        }
        DenseArray::new(mlpl_array::Shape::new(vec![m, k]), data).expect("shape")
    } else {
        upstream
            .matmul(&b.transpose())
            .expect("matmul upstream b^T")
    }
}

//! Reduction, shape, and matmul methods on [`Tensor`].

use std::rc::Rc;

use mlpl_array::{DenseArray, Shape};

use crate::softmax::softmax_forward;
use crate::tape::{NodeData, NodeKind};
use crate::tensor::Tensor;

fn new_tensor(t: &Tensor, value: DenseArray, kind: NodeKind) -> Tensor {
    let node = t.tape.push(NodeData {
        value,
        grad: None,
        kind,
        requires_grad: false,
    });
    Tensor {
        node,
        tape: Rc::clone(&t.tape),
    }
}

impl Tensor {
    /// Sum all elements into a scalar.
    #[must_use]
    pub fn sum(&self) -> Self {
        let s: f64 = self.value().data().iter().sum();
        new_tensor(
            self,
            DenseArray::from_scalar(s),
            NodeKind::SumAll { parent: self.node },
        )
    }

    /// Mean over all elements.
    #[must_use]
    pub fn mean(&self) -> Self {
        let v = self.value();
        let n = v.data().len() as f64;
        let s: f64 = v.data().iter().sum();
        new_tensor(
            self,
            DenseArray::from_scalar(s / n),
            NodeKind::MeanAll { parent: self.node },
        )
    }

    /// Softmax along the last axis (rank-1 or rank-2 inputs).
    #[must_use]
    pub fn softmax(&self) -> Self {
        let v = self.value();
        let axis = v.shape().rank().saturating_sub(1);
        let y = softmax_forward(&v, axis);
        new_tensor(
            self,
            y,
            NodeKind::Softmax {
                parent: self.node,
                axis,
            },
        )
    }

    /// Transpose: reverse axes.
    #[must_use]
    pub fn transpose(&self) -> Self {
        let v = self.value().transpose();
        new_tensor(self, v, NodeKind::Transpose { parent: self.node })
    }

    /// Reshape to `new_shape` (must preserve element count).
    #[must_use]
    pub fn reshape(&self, new_shape: Shape) -> Self {
        let v_orig = self.value();
        let orig_shape = v_orig.shape().clone();
        let v = v_orig.reshape(new_shape).expect("compatible reshape");
        new_tensor(
            self,
            v,
            NodeKind::Reshape {
                parent: self.node,
                orig_shape,
            },
        )
    }

    /// Matrix multiplication `self @ other`.
    #[must_use]
    pub fn matmul(&self, other: &Self) -> Self {
        let v = self
            .value()
            .matmul(&other.value())
            .expect("compatible matmul shapes");
        new_tensor(
            self,
            v,
            NodeKind::MatMul {
                left: self.node,
                right: other.node,
            },
        )
    }

    /// Clone of the tape handle.
    #[must_use]
    pub fn tape_rc(&self) -> Rc<crate::tape::Tape> {
        Rc::clone(&self.tape)
    }
}

